async function fetchCands(pg,ps,f){pg=pg||1;ps=ps||20;f=f||{};var u=MAN+"/candidates/?page="+pg+"&page_size="+ps;if(f.source_type&&f.source_type!=="all")u+="&source_type="+f.source_type;if(f.search)u+="&full_name="+encodeURIComponent(f.search)+"&case_insensitive=true";if(f.position)u+="&current_position="+encodeURIComponent(f.position);if(f.desc)u+="&description="+encodeURIComponent(f.desc);if(f.location)u+="&candidate_location="+encodeURIComponent(f.location);var r=await fetch(u,{headers:{"Authorization":"Token "+MT}});if(!r.ok)throw new Error("Manatal "+r.status);var d=await r.json();return{candidates:d.results||[],total:d.count||0,hasNext:!!d.next,hasPrev:!!d.previous}}
async function fetchJobs(pg,ps){pg=pg||1;ps=ps||20;var r=await fetch(MAN+"/jobs/?page="+pg+"&page_size="+ps+"&status=active",{headers:{"Authorization":"Token "+MT}});if(!r.ok)throw new Error("Jobs "+r.status);var d=await r.json();return{jobs:d.results||[],total:d.count||0,hasNext:!!d.next,hasPrev:!!d.previous}}
async function fetchOrgs(){var r=await fetch(MAN+"/organizations/?page_size=50",{headers:{"Authorization":"Token "+MT}});if(!r.ok)return[];var d=await r.json();return d.results||[]}
async function fetchJobMatches(jobId){var r=await fetch(MAN+"/matches/?job_id="+jobId+"&page_size=100",{headers:{"Authorization":"Token "+MT}});if(!r.ok)return[];var d=await r.json();return d.results||[]}
async function logNote(id,txt){await fetch(MAN+"/candidates/"+id+"/notes/",{method:"POST",headers:{"Authorization":"Token "+MT,"Content-Type":"application/json"},body:JSON.stringify({info:txt})})}
async function fetchJobNotes(jobId){try{var r=await fetch(MAN+"/jobs/"+jobId+"/notes/",{headers:{"Authorization":"Token "+MT}});if(!r.ok)return"";var d=await r.json();var notes=(d.result||d.results||[]);return notes.map(function(n){return strip(n.info||"")}).join("\n")}catch(e){return""}}
function wait(ms){return new Promise(function(r){setTimeout(r,ms)})}
async function safeFetch(pg,ps,f){try{var r=await fetchCands(pg,ps,f);return r}catch(e){return{candidates:[],total:0,hasNext:false,hasPrev:false}}}
function getMatchCache(jobId){try{var c=JSON.parse(window.localStorage.getItem("matchCache_"+jobId));if(c&&c.ts&&Date.now()-c.ts<14400000)return c.matches;return null}catch(e){return null}}
function setMatchCache(jobId,matches){try{window.localStorage.setItem("matchCache_"+jobId,JSON.stringify({ts:Date.now(),matches:matches.map(function(m){return{id:m.id,full_name:m.full_name,email:m.email,current_position:m.current_position,current_company:m.current_company,candidate_location:m.candidate_location,latest_degree:m.latest_degree,latest_university:m.latest_university,source_type:m.source_type,description:m.description,resume:m.resume,_applied:m._applied,_scores:m._scores}})}))}catch(e){}}
async function matchCandidates(job,onStatus){
var cached=getMatchCache(job.id);
if(cached&&cached.length>0){onStatus("Loaded cached results. Run match again to refresh.");return cached}
onStatus("Step 1/6: Loading screening criteria and applicants...");
var jobDesc=strip(job.description||"").substring(0,2000);
var jobNotes="";try{jobNotes=await fetchJobNotes(job.id)}catch(e){}
var all=[];var seen={};
await wait(300);
try{var appMatches=await fetchJobMatches(job.id);var appCands=appMatches.slice(0,15);for(var ai=0;ai<appCands.length;ai++){var am=appCands[ai];await wait(400);try{var acr=await fetch(MAN+"/candidates/?id="+am.candidate,{headers:{"Authorization":"Token "+MT}});if(acr.ok){var acd=await acr.json();var ac=(acd.results&&acd.results[0])||null;if(ac&&!seen[ac.id]){seen[ac.id]=true;ac._applied=true;all.push(ac)}}}catch(e){}}}catch(e){}
onStatus("Step 2/6: Found "+all.length+" applicants. Generating search strategy...");
await wait(400);
var kwRes=await fetch(API,{method:"POST",headers:AH,body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:300,messages:[{role:"user",content:"You are helping search a recruiting database. Extract search terms from this job posting.\n\nReturn a JSON object with:\n- keywords: array of 8 SINGLE-WORD technical skills/tools (e.g. 'Python', 'Kafka', 'React')\n- titles: array of 3 SINGLE-WORD job title terms (e.g. 'Backend', 'Engineer', 'Developer')\n- companies: array of 3 company names where ideal candidates might work (e.g. 'Google', 'Stripe')\n\nReturn ONLY the JSON object.\n\nJob: "+job.position_name+"\nDescription: "+jobDesc.substring(0,1000)}]})});
var kwData=await kwRes.json();var kws=[],titles=[],companies=[];
try{var parsed=JSON.parse((kwData.content||[]).map(function(b){return b.text||""}).join("").replace(/```json|```/g,"").trim());kws=parsed.keywords||[];titles=parsed.titles||[];companies=parsed.companies||[]}catch(e){kws=job.position_name.split(" ").filter(function(w){return w.length>3})}
var allSearchTerms=kws.concat(titles).filter(function(v,i,a){return a.indexOf(v)===i});
onStatus("Step 3/6: Searching "+allSearchTerms.length+" keywords + "+companies.length+" companies...");
for(var ki=0;ki<allSearchTerms.length;ki++){var kw=allSearchTerms[ki];
onStatus("Step 3/6: Searching '"+kw+"' ("+(ki+1)+"/"+allSearchTerms.length+")...");
await wait(500);
var r1=await safeFetch(1,20,{position:kw});
for(var ci=0;ci<r1.candidates.length;ci++){var c=r1.candidates[ci];if(!seen[c.id]){seen[c.id]=true;all.push(c)}}
if(ki<4){await wait(500);var r2=await safeFetch(1,20,{desc:kw});for(var ci2=0;ci2<r2.candidates.length;ci2++){var c2=r2.candidates[ci2];if(!seen[c2.id]){seen[c2.id]=true;all.push(c2)}}}
if(r1.hasNext&&ki<3){await wait(500);var r3=await safeFetch(2,20,{position:kw});for(var ci3=0;ci3<r3.candidates.length;ci3++){var c3=r3.candidates[ci3];if(!seen[c3.id]){seen[c3.id]=true;all.push(c3)}}}
if(all.length>150)break}
for(var coi=0;coi<companies.length&&all.length<180;coi++){await wait(500);onStatus("Step 3/6: Searching company '"+companies[coi]+"'...");var cr=await safeFetch(1,15,{desc:companies[coi]});for(var cci=0;cci<cr.candidates.length;cci++){var cc=cr.candidates[cci];if(!seen[cc.id]){seen[cc.id]=true;all.push(cc)}}}
var jobLoc=(job.address||"").split(",")[0].trim();
if(jobLoc&&jobLoc.length>2){await wait(500);var lr=await safeFetch(1,20,{location:jobLoc});for(var li=0;li<lr.candidates.length;li++){var lc=lr.candidates[li];if(!seen[lc.id]){seen[lc.id]=true;all.push(lc)}}}
// === RECRUITERFLOW CANDIDATE SEARCH ===
var rfCount=0;
try{
onStatus("Step 3b/6: Searching RecruiterFlow AEC database (10,000+ candidates)...");
var rfSkills=allSearchTerms.slice(0,8).map(function(k){return[k]});
var rfRes=await fetch("/api/recruiterflow",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"matchCandidates",params:{skillSets:rfSkills,maxTotal:200}})});
if(rfRes.ok){var rfData=await rfRes.json();var rfCands=rfData.candidates||[];
for(var ri=0;ri<rfCands.length;ri++){var rc=rfCands[ri];var rfKey="rf_"+rc.rf_id;if(!seen[rfKey]){seen[rfKey]=true;all.push({id:"rf_"+rc.rf_id,full_name:rc.full_name,email:rc.email,current_position:rc.current_position,current_company:rc.current_company,candidate_location:"",latest_degree:"",latest_university:"",source_type:"recruiterflow",description:rc.resume_text||"",_source:"RecruiterFlow",_skills:(rc.skills||[]).join(", ")});rfCount++}}
onStatus("Step 3b/6: Added "+rfCount+" from RecruiterFlow ("+rfData.totalSearches+" skill searches, "+rfData.count+" found, "+all.length+" total pool)");}
}catch(e){console.log("RF search error:",e)}
// === END RECRUITERFLOW ===
onStatus("Step 4/6: Building enriched profiles for "+all.length+" candidates...");
var cList=all.map(function(c){var desc=(c.description||"").substring(0,2000);var profile={id:c.id,name:c.full_name,email:c.email,position:c.current_position,company:c.current_company,location:c.candidate_location,degree:c.latest_degree,university:c.latest_university,source:c.source_type,applied:c._applied?"YES":"no"};if(desc.length>50)profile.resume_text=desc;return JSON.stringify(profile)});
var notesCtx=jobNotes?"\n\nSCREENING CRITERIA AND CLIENT FEEDBACK (CRITICAL - follow these strictly):\n"+jobNotes.substring(0,1500):"";
onStatus("Step 5/6: AI ranking "+all.length+" candidates with enriched profiles...");
var rankBody={model:"claude-sonnet-4-20250514",max_tokens:2000,messages:[{role:"user",content:"You are an expert technical recruiter at a top staffing firm. Analyze each candidate against this job and select the BEST 3.\n\nSCORING RUBRIC (score each 0-100):\n1. SKILLS MATCH (40%): Do their technical skills align with requirements?\n2. EXPERIENCE LEVEL (25%): Right years and depth of relevant experience?\n3. INDUSTRY FIT (15%): Similar companies or domains?\n4. LOCATION (10%): Near the job location or is it remote?\n5. EDUCATION (10%): Does education support the role?\n\nCRITICAL RULES:\n- Candidates marked applied=YES have already applied to THIS job. STRONGLY prioritize unless clearly unqualified.\n- Follow screening criteria and auto-reject triggers STRICTLY if provided.\n- Use resume_text to deeply evaluate actual experience and skills.\n- Consider company pedigree - candidates from well-known tech companies or YC startups score higher.\n- Evaluate candidates thoroughly based on their resume text, company pedigree, and education.\n\nJOB TITLE: "+job.position_name+"\nLOCATION: "+(job.address||"Not specified")+"\nSALARY: $"+(job.salary_min||"?")+" - $"+(job.salary_max||"?")+"\nREMOTE: "+(job.is_remote?"Yes":"No")+"\nCONTRACT: "+(job.contract_details||"full_time")+"\nDESCRIPTION:\n"+jobDesc+notesCtx+"\n\nCANDIDATES ("+all.length+" total):\n"+cList.join("\n")+"\n\nIMPORTANT: Your final output MUST end with ONLY a JSON array. No commentary after the array.\n[{\"id\":123,\"overall\":85,\"skills\":90,\"experience\":80,\"industry\":75,\"location\":90,\"education\":85,\"reason\":\"2-3 sentence reason citing specific experience\"}]\n\nOverall = skills*0.4 + experience*0.25 + industry*0.15 + location*0.1 + education*0.1"}]};
var rankRes=await fetch(API,{method:"POST",headers:AH,body:JSON.stringify(rankBody)});
var rankData=await rankRes.json();var rankTxt=(rankData.content||[]).map(function(b){return b.text||""}).join("");
onStatus("Step 6/6: Processing results...");
var jsonMatch=rankTxt.match(/\[\s*\{[\s\S]*?\}\s*\]/);
if(!jsonMatch)jsonMatch=rankTxt.match(/\[[\s\S]*\]/);
try{var scored=JSON.parse((jsonMatch?jsonMatch[0]:rankTxt).replace(/```json|```/g,"").trim());var scoreMap={};scored.forEach(function(s){scoreMap[String(s.id)]=s});var matched=all.filter(function(c){return scoreMap[String(c.id)]}).slice(0,3);if(matched.length===0){var scoredIds=scored.map(function(s){return Number(s.id)});matched=all.filter(function(c){return scoredIds.indexOf(c.id)!==-1}).slice(0,3)}if(matched.length===0&&scored.length>0){matched=scored.map(function(s){var found=all.find(function(a){return a.id===s.id||a.id===Number(s.id)||String(a.id)===String(s.id)});if(!found)found=all[0];if(found){found=Object.assign({},found);found._scores=s}return found}).filter(Boolean).slice(0,3)}else{matched.forEach(function(c){c._scores=scoreMap[String(c.id)]||{}})}setMatchCache(job.id,matched);return matched}catch(e){console.log("Score parse error:",e,rankTxt);var fallback=all.filter(function(c){return c.email}).slice(0,3);return fallback}}
