var doGen=async function(){setGen(true);setSubj("");setBody("");
var ctx=compTargets.filter(function(c){return c.email}).slice(0,3).map(function(c){return c.full_name+": "+c.current_position+" at "+c.current_company+" | "+(c.description||"").substring(0,100)}).join("; ");
var jobCtx=massJob?("SPECIFIC ROLE: "+massJob.position_name+"\nLOCATION: "+(massJob.address||"Not specified")+"\nSALARY: $"+(massJob.salary_min||"?")+" - $"+(massJob.salary_max||"?")+"\nFULL JOB DESCRIPTION:\n"+strip(massJob.description||"").substring(0,800)):"Role: "+jobTitle;
var prompt="";
if(emailType==="screening"){
prompt="Generate a screening email for shortlisted candidates. Return ONLY JSON: {\"subject\":\"...\",\"body\":\"...\"}\n\nThe email MUST:\n1. Thank them for applying to THIS SPECIFIC position (use the exact job title and location from the job details below - DO NOT use Account Executive or any other role name unless that is the actual role)\n2. Tell them they are shortlisted\n3. Ask them to reply with:\n   * Desired salary\n   * LinkedIn URL\n   * Current location\n   * Work authorization status\n   * Answer to: What is the most impressive thing you have done?\n   * Confirmation of location preference (use ACTUAL locations from job)\n   * ONE custom screening question that is SPECIFIC to the requirements listed in the job description below and relevant to the candidates background. The question should test a KEY SKILL or REQUIREMENT from THIS specific job posting\n\nJob: "+jobCtx+"\nCandidates: "+ctx+"\nUse {name} for first name. Professional tone. Use \\n for newlines, * for bullets."}
else{prompt="Write a cold outreach email. Return ONLY JSON: {\"subject\":\"...\",\"body\":\"...\"}\n"+jobCtx+". Tone: "+tone+". Candidates: "+ctx+"\nMerge vars: {name} {position} {company}. Under 100 words. No markdown."}
try{var r=await fetch(API,{method:"POST",headers:AH,body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:800,messages:[{role:"user",content:prompt}]})});var d=await r.json();var txt=d.content?d.content.map(function(b){return b.text||""}).join(""):("");var p=JSON.parse(txt.replace(/```json|```/g,"").trim());setSubj(p.subject||"");setBody(p.body||"")}catch(e){setSubj("Opportunity - {name}");setBody("Hi {name},\n\nWe are interested in your background.\n\nBest regards")}setGen(false)};
var merge=function(raw,c){if(!raw||!c)return raw||"";return raw.replace(/\{name\}/g,(c.full_name||"").split(" ")[0]||"").replace(/\{first_name\}/g,(c.full_name||"").split(" ")[0]||"").replace(/\{position\}/g,c.current_position||"").replace(/\{company\}/g,c.current_company||"")};
var doSend=function(c){var s=merge(subj,c),b=merge(body,c);gmail(c.email,s,b);if(emailType==="screening"&&massJob){var pe={id:Math.random().toString(36).substr(2,9),candidateId:c.id,candidateName:c.full_name,candidateEmail:c.email,candidatePosition:c.current_position,candidateCompany:c.current_company,candidateLocation:c.candidate_location,jobId:massJob.id,jobTitle:massJob.position_name,jobOrg:massJob.organization,screenedAt:new Date().toISOString(),status:"screened",reply:"",submittedTo:"",submittedAt:null};savePipeline([pe].concat(pipeline))}setSent(function(p){return[{id:Math.random(),name:c.full_name,email:c.email,subject:s,time:new Date().toLocaleString(),logged:false}].concat(p)});toast({title:"Gmail opened for "+(c.full_name||"").split(" ")[0],status:"success"});logNote(c.id,"Outreach: "+s).then(function(){setSent(function(p){return p.map(function(e){return e.name===c.full_name?Object.assign({},e,{logged:true}):e})})}).catch(function(){})};
var doMassCompose=function(job,matched){setMassJob(job);setCompTargets(matched.filter(function(c){return c.email}));setJobTitle(job.position_name);setSubMode(false);setTab("compose")};
var openSubmit=function(candidate,job){setSubCandidate(candidate);setSubJob(job);setSubReply("");setSubRecipient("");setSubRecType("client");setSubSubj("");setSubBody("");setSubMode(true);setTab("compose")};
var doSubGen=async function(){setSubGen(true);setSubSubj("");setSubBody("");var c=subCandidate;var j=subJob;var jobDesc=strip(j?j.description||"":"").substring(0,400);
var prompt="Generate a candidate submission email. Return ONLY JSON: {\"subject\":\"...\",\"body\":\"...\"}\n\nYou are submitting a candidate to a "+(subRecType==="client"?"client":"internal hiring team member")+".\n\nThe email MUST follow this EXACT structure:\n\nSECTION 1 - CANDIDATE DETAILS (at the very top):\nExtract these from the screening reply and list them clearly:\n- Name: "+c.full_name+"\n- Desired Salary\n- LinkedIn URL\n- Current Location\n- Work Authorization Status\n- Location Preference/Confirmation\n- Their answer to: What is the most impressive thing you have done?\n- Their answer to the custom screening question\nIf any are not in the screening reply, use profile data or mark as Not provided.\n\nSECTION 2 - CANDIDATE SUBMISSION SUMMARY (EXACTLY 2000 characters):\nA persuasive narrative explaining why this candidate is an excellent fit. Weave in their screening responses naturally. Do not repeat Section 1 verbatim.\n\nSECTION 3 - CLOSING:\nNote that resume is attached (PDF) and call to action to schedule an interview.\n\nCANDIDATE PROFILE:\n- Current Role: "+(c.current_position||"N/A")+" at "+(c.current_company||"N/A")+"\n- Location: "+(c.candidate_location||"N/A")+"\n- Education: "+(c.latest_degree||"N/A")+" from "+(c.latest_university||"N/A")+"\n- Email: "+(c.email||"N/A")+"\n- Phone: "+(c.phone_number||"N/A")+"\n\nJOB: "+j.position_name+"\nJOB DESCRIPTION: "+jobDesc+"\nJOB LOCATION: "+(j.address||"Not specified")+"\nSALARY: $"+(j.salary_min||"?")+" - $"+(j.salary_max||"?")+"\n\nSCREENING REPLY FROM CANDIDATE:\n"+(subReply||"No screening response provided")+"\n\nRecipient type: "+subRecType+"\nUse \\n for newlines. Professional tone. No markdown backticks.";
try{var r=await fetch(API,{method:"POST",headers:AH,body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:2000,messages:[{role:"user",content:prompt}]})});var d=await r.json();var txt=d.content?d.content.map(function(b){return b.text||""}).join(""):("");var p=JSON.parse(txt.replace(/```json|```/g,"").trim());setSubSubj(p.subject||"");setSubBody(p.body||"")}catch(e){setSubSubj("Candidate Submission: "+c.full_name+" for "+j.position_name);setSubBody("CANDIDATE DETAILS:\nName: "+c.full_name+"\nCurrent Role: "+(c.current_position||"N/A")+" at "+(c.current_company||"N/A")+"\nLocation: "+(c.candidate_location||"N/A")+"\nEmail: "+(c.email||"N/A")+"\n\nSCREENING RESPONSE:\n"+(subReply||"Not provided")+"\n\n[AI summary generation failed - API may be temporarily overloaded. Click Generate Submission to retry.]")}setSubGen(false)};
var doSubSend=function(){if(!subRecipient||!subSubj||!subBody)return;gmail(subRecipient,subSubj,subBody);if(subCandidate&&subJob){var updatedPL=pipeline.map(function(x){return x.candidateId===subCandidate.id&&x.jobId===subJob.id&&x.status==="replied"?Object.assign({},x,{status:"submitted",submittedTo:subRecipient,submittedAt:new Date().toISOString()}):x});savePipeline(updatedPL)}setSent(function(p){return[{id:Math.random(),name:subCandidate.full_name,email:subRecipient,subject:subSubj,time:new Date().toLocaleString(),logged:false,type:"submission"}].concat(p)});toast({title:"Submission email opened",detail:"To: "+subRecipient,status:"success"});logNote(subCandidate.id,"Submitted to "+subRecType+": "+subRecipient+" for "+subJob.position_name).catch(function(){})};
var filteredJobs=jobs.filter(function(j){return(!jobSearch||j.position_name.toLowerCase().indexOf(jobSearch.toLowerCase())!==-1)&&(clientFilter==="all"||j.organization===clientFilter)}).sort(function(a,b){if(jobSort==="newest")return new Date(b.created_at)-new Date(a.created_at);if(jobSort==="oldest")return new Date(a.created_at)-new Date(b.created_at);return a.position_name.localeCompare(b.position_name)});
